INSERT INTO countries (id, name, default_lat, default_lng, default_zoom) VALUES ('se', 'Sverige', 62, 17, 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('frigoerelsen', 'se', 'Frigörelsen', 1520, 1560) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('expansion', 'se', 'Expansion', 1560, 1630) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('stormakt', 'se', 'Stormaktstid', 1630, 1718) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('fall', 'se', 'Stormaktens fall', 1718, 1721) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('frihetstid', 'se', 'Frihetstid', 1721, 1772) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('gustaviansk', 'se', 'Gustaviansk tid', 1772, 1809) ON CONFLICT (id) DO NOTHING;
INSERT INTO eras (id, country_id, label, year_from, year_to) VALUES ('slutet', 'se', 'Mot freden', 1809, 1814) ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p001', 'Gustav Vasa', 1496, 1560, 'GV', 'Kung av Sverige 1523–1560. Ledde upproret mot Danmark efter Stockholms blodbad, bröt Sverige ur Kalmarunionen och grundade i praktiken det moderna Sverige. Genomförde även reformationen och gjorde kyrkan statlig.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p002', 'Kristian II', 1481, 1559, 'K2', 'Kung av Danmark, Norge och Sverige. Beordrade Stockholms blodbad 1520 i ett försök att befästa dansk kontroll över Sverige. Handlingen fick motsatt effekt och utlöste det uppror som bröt unionen.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p003', 'Gustav II Adolf', 1594, 1632, 'GA', 'Kung av Sverige 1611–1632, kallad ''Lejonet från Norden''. Under hans ledning blev Sverige en europeisk stormakt. Dödades i slaget vid Lützen 1632 och blev en av historiens mest omtalade krigarkungarna.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p004', 'Axel Oxenstierna', 1583, 1654, 'AO', 'Rikskansler under Gustav II Adolf och sedan förmyndare för drottning Kristina. En av de mest inflytelserika statsmännen i svensk historia. Ledde Sverige genom stora delar av Trettioåriga kriget efter kungens död.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p005', 'Karl X Gustav', 1622, 1660, 'KXG', 'Kung av Sverige 1654–1660. Ledde de spektakulära vinterfälttågen över de danska sunden 1658 och tvingade Danmark att avträda Skåne, Blekinge och Halland i freden i Roskilde.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p006', 'Karl XI', 1655, 1697, 'K11', 'Kung av Sverige 1660–1697. Besegrade Danmark vid Lund 1676 och genomförde sedan den stora reduktionen – återförde adelns gods till kronan och skapade en starkare centralmakt.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p007', 'Karl XII', 1682, 1718, 'K12', 'Kung av Sverige 1697–1718. Militärt genial men strategiskt kostsam. Vann spektakulära segrar vid Narva och Kliszów men förlorade allt vid Poltava 1709. Sköts vid belägringen av Fredrikshald under oklara omständigheter.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p008', 'Peter den Store', 1672, 1725, 'PdS', 'Tsar av Ryssland 1682–1725. Moderniserade Ryssland efter västerländsk modell. Besegrades katastrofalt av Karl XII vid Narva men använde nederlaget för att reformera sin armé och segrade slutligen vid Poltava 1709.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p009', 'Magnus Stenbock', 1665, 1717, 'MS', 'Svensk fältmarskalk och en av Karl XII:s främsta generaler. Vann den sista svenska storsegern vid Gadebusch 1712 men kapitulerade sedan vid Tönning 1713 och dog i dansk fångenskap.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p010', 'Ulrika Eleonora', 1688, 1741, 'UE', 'Drottning av Sverige 1718–1720, syster till Karl XII. Abdikerade till förmån för sin make Fredrik I. Under hennes korta regering inleddes arbetet med den nya frihetstida författningen som begränsade kungamakten.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p011', 'Arvid Horn', 1664, 1742, 'AH', 'Ledande statsman under frihetstiden och ledare för mösspartiet. Förespråkade fred och återhållsamhet efter stormaktstidens kostsamma krig. Dominerade svensk politik under 1720-talet.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p012', 'Gustaf III', 1746, 1792, 'G3', 'Kung av Sverige 1771–1792. Genomförde statskupp 1772 och återupprättade kungamakten. Kulturellt briljant men politiskt kontroversiell. Startade krig mot Ryssland 1788 och mördades på en maskeradbal 1792.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p013', 'Gustaf IV Adolf', 1778, 1837, 'G4', 'Kung av Sverige 1792–1809. Envist antinapoleonsk och förde Sverige in i katastrofala krig. Förlorade Finland till Ryssland 1809 och avsattes i en militärkupp samma år – den siste svenska kungen att avsättas.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p014', 'Jean-Baptiste Bernadotte', 1763, 1844, 'JB', 'Fransk marskalk under Napoleon, vald till svensk kronprins 1810 som Karl Johan. Vände Sverige mot Napoleon, erövrade Norge från Danmark 1814 och slöt fred. Blev kung Karl XIV Johan 1818.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p015', 'Lennart Torstenson', 1603, 1651, 'LT', 'Svensk fältmarskalk, en av de skickligaste i Trettioåriga kriget. Känd för sina snabba marscher och offensiva artilleriföring. Ledde det svenska angreppet på Danmark 1643–1645 i det så kallade Torstensonkriget.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p016', 'Ivan Mazepa', 1639, 1709, 'IM', 'Kosackhetman i Ukraina, allierade sig med Karl XII mot Peter den Store inför Poltava-kampanjen. Hoppades på ett självständigt Ukraina men alliansen slutade i katastrof vid Poltava 1709.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p017', 'Fredrik I', 1676, 1751, 'F1', 'Kung av Sverige 1720–1751. Makten låg reellt hos riksrådet under frihetstiden. Sverige förlorade stormaktsställningen under hans tid men upplevde också en period av relativ fred och ekonomisk återhämtning.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO persons (id, name, born, died, initials, description, country_id) VALUES ('se_p018', 'Kristina', 1626, 1689, 'KR', 'Drottning av Sverige 1632–1654, dotter till Gustav II Adolf. Excentrisk och bildad regent som avslutade Trettioåriga kriget med freden i Westfalen 1648. Abdikerade frivilligt, konverterade till katolicismen och levde resten av livet i Rom.', 'se') ON CONFLICT (id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e001', 'se', 'event', 'frigoerelsen', 'Stockholms blodbad', '8–9 november 1520', 1520, 59.325, 18.071, 'Stockholm, Sverige', 'Kalmarunionen, 1520', 'Kung Kristian II av Danmark lät avrätta uppemot 90 personer – biskopar, adelsmän och borgare – på Stortorget i Stockholm. Det var ett försök att befästa dansk kontroll genom terror. Handlingen fick rakt motsatt effekt: den utlöste ett uppror som för alltid bröt Sverige ur Kalmarunionen.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e001', 'se_p002', 'Beordrade massakern') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e001', 'se_p001', 'Förlorade sin far i blodbadet, ledde upproret som följde') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e002', 'se', 'event', 'frigoerelsen', 'Gustav Vasa väljs till kung', '6 juni 1523', 1523, 57.782, 14.156, 'Strängnäs, Sverige', 'Sverige, 1523', 'Gustav Vasa väljs till kung av Sverige på riksdagen i Strängnäs. Sverige bröt officiellt ur Kalmarunionen och Danmark förlorade kontrollen över riket. Den 6 juni firas idag som Sveriges nationaldag.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e002', 'se_p001', 'Vald till kung, grundare av Vasadynastin') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e003', 'se', 'event', 'frigoerelsen', 'Reformationen genomförs', '1527', 1527, 59.325, 18.071, 'Västerås, Sverige', 'Kungariket Sverige, 1527', 'På riksdagen i Västerås bröt Sverige med Rom och kyrkan underställdes kronan. Kyrkans gods konfiskerades och gav Gustav Vasa den ekonomiska bas han behövde för att konsolidera makten. En av de mest omvälvande politiska förändringarna i svensk historia.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e003', 'se_p001', 'Drev igenom reformationen av politiska och ekonomiska skäl') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e004', 'se', 'battle', 'expansion', 'Nordiska sjuårskriget börjar', '1563', 1563, 56.046, 12.694, 'Helsingborg, Sverige', 'Kungariket Sverige, 1563', 'Sverige hamnade i krig mot Danmark, Lübeck och Polen i ett av de blodigaste nordiska krigen på 1500-talet. Konflikten handlade om kontrollen över Östersjöhandeln och de strategiska sunden. Kriget slutade i status quo 1570 men kostade enormt i liv och resurser.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e005', 'se', 'battle', 'expansion', 'Slaget i Kalmar sund', '31 maj – 1 juni 1611', 1611, 56.661, 16.362, 'Kalmar sund, Sverige', 'Kalmarkriget, 1611', 'Danmark angrep Sverige i Kalmarkriget och tog Kalmar fästning. Det var ett av de tyngre nederlaget för Sverige under denna period. Det unga Karl II:s (senare Gustav II Adolf) första eldprov som ledare.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e005', 'se_p003', 'Ung kung på sitt första fälttåg') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e006', 'se', 'battle', 'stormakt', 'Slaget vid Breitenfeld', '17 september 1631', 1631, 51.427, 12.373, 'Breitenfeld, Tyskland', 'Det Heliga Romerska Riket, 1631', 'Sveriges första stora seger i Trettioåriga kriget och en av de viktigaste protestanska segrarna i hela konflikten. Gustav II Adolf besegrade den kejserliga armén och förvandlade Sverige till Europas ledande militärmakt. Segern räddade den protestantiska saken i Tyskland.', NULL, NULL, 'Sveriges inträde i Trettioåriga kriget – landstigning och marsch söderut') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e006', 'se_p003', 'Överbefälhavare, avgörande seger') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e006', 0, 56.16, 15.59, 'Kalmar – embarkeringen');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e006', 1, 54.09, 13.38, 'Peenemünde – landstigning i Tyskland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e006', 2, 52.52, 13.41, 'Berlin-trakten – alliansen med Brandenburg');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e006', 3, 51.43, 12.37, 'Breitenfeld – den avgörande segern');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e007', 'se', 'battle', 'stormakt', 'Slaget vid Lützen', '16 november 1632', 1632, 51.252, 12.141, 'Lützen, Tyskland', 'Det Heliga Romerska Riket, 1632', 'Sverige vann slaget men förlorade sin kung. Gustav II Adolf sköts under drabbningen och dog på slagfältet. Hans död chockade hela Europa. Trots förlusten av kungen höll den svenska armén och segrade – men stormaktsprojektet förlorade sin drivande kraft.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e007', 'se_p003', 'Kung av Sverige, stupade i striden') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e007', 'se_p004', 'Övertog ledningen av Sverige och kriget efter kungens död') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e008', 'se', 'event', 'stormakt', 'Freden i Westfalen', '24 oktober 1648', 1648, 51.962, 7.625, 'Osnabrück/Münster, Tyskland', 'Det Heliga Romerska Riket, 1648', 'Trettioåriga kriget avslutades. Sverige fick betydande territorier i norra Tyskland och erkändes som en av Europas stormakter. Freden i Westfalen anses ofta som startpunkten för det moderna statssystemet i Europa.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e008', 'se_p004', 'Ledde de svenska förhandlingarna') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e008', 'se_p018', 'Drottning av Sverige, ratificerade freden') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e009', 'se', 'battle', 'stormakt', 'Torstensonkriget mot Danmark', '1643–1645', 1643, 56.15, 10.22, 'Jylland, Danmark', 'Kungariket Danmark, 1643', 'Sverige angrep Danmark utan förklaring och Lennart Torstensons armé marscherade blixtsnabbt genom Jylland. Kriget slutade med freden i Brömsebro 1645 där Danmark avträdde Gotland, Ösel och Jämtland till Sverige – ett stort steg mot svensk dominans i Norden.', NULL, NULL, 'Torstensons blixtkrig – armén svepte genom Jylland på rekordtid') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e009', 'se_p015', 'Överbefälhavare för den svenska armén') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e009', 0, 55.71, 13.19, 'Malmö – utgångspunkt');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e009', 1, 55.47, 9.47, 'Kolding, Jylland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e009', 2, 56.46, 9.98, 'Viborg, norra Jylland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e009', 3, 57.05, 9.92, 'Ålborg – armén kontrollerar Jylland');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e010', 'se', 'battle', 'stormakt', 'Tåget över Bält', 'januari–februari 1658', 1658, 55.45, 10.5, 'Lilla Bält och Stora Bält, Danmark', 'Kungariket Danmark, 1658', 'En av historiens mest djärvaste militära manövrar. Karl X Gustav ledde sin armé till fots över de frusna danska sunden under vintern. Det var ett drag ingen danskt befäl ansåg möjligt. Rörelsen kringgick alla danska försvar och tvingade Danmark till förhandlingsbordet.', NULL, NULL, 'Marschen över isen – ett drag ingen danskt befäl ansåg möjligt') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e010', 'se_p005', 'Kung av Sverige, planerade och ledde den riskfyllda manövern') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 0, 55.6, 13, 'Malmö – armén samlas');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 1, 55.49, 9.75, 'Kolding, Fyn-sidan');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 2, 55.39, 10.38, 'Fyn – Lilla Bält korsas');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 3, 55.46, 11.56, 'Sprogø – mitt på Stora Bält');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 4, 55.53, 11.99, 'Korsör, Själland – isen håller');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e010', 5, 55.64, 12.08, 'Roskilde – Danmark ger upp');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e011', 'se', 'event', 'stormakt', 'Freden i Roskilde', '26 februari 1658', 1658, 55.641, 12.08, 'Roskilde, Danmark', 'Kungariket Danmark, 1658', 'Danmark tvingades avträda Skåne, Blekinge, Halland, Bornholm och Trondheims len till Sverige. Det var Sveriges territoriella höjdpunkt och skapade i stort sett den moderna svenska-danska gränsen. Bornholm och Trondheim återfick Danmark kort därefter, men Skåne förblev svenskt.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e011', 'se_p005', 'Kung av Sverige, dikterade fredsvillkoren') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e012', 'se', 'battle', 'stormakt', 'Slaget vid Lund', '4 december 1676', 1676, 55.705, 13.19, 'Lund, Sverige', 'Skåne, Sverige (nyligen erövrat från Danmark), 1676', 'Det blodigaste slaget i Skandinaviens historia. Danmark hade återtagit stora delar av Skåne och hotade att vinna tillbaka provinsen. Karl XI mötte den danska armén utanför Lund. Uppskattningsvis 9 000 soldater dödades under några timmar. Sverige segrade och behöll Skåne.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e012', 'se_p006', 'Kung av Sverige, ledde personligen kavalleriet till seger') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e013', 'se', 'battle', 'stormakt', 'Slaget vid Landskrona', '14 juli 1677', 1677, 55.871, 12.83, 'Landskrona, Sverige', 'Skåne, Sverige, 1677', 'Karl XI besegrade återigen den danska armén, nu vid Landskrona. Segern befäste svensk kontroll över Skåne definitivt. Danmarks sista realistiska chans att återta de förlorade provinserna gick om intet.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e013', 'se_p006', 'Kung av Sverige, segrare') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e014', 'se', 'event', 'stormakt', 'Den stora reduktionen', '1680', 1680, 59.325, 18.071, 'Stockholm, Sverige', 'Kungariket Sverige, 1680', 'Karl XI genomförde reduktionen – återförde adelns gods till kronan. En fjärdedel av Sveriges jord bytte ägare. Det var en av de mest genomgripande ekonomiska reformerna i svensk historia och skapade den finansiella bas som Karl XII senare spenderade på krigen.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e014', 'se_p006', 'Kung av Sverige, drev igenom reformen mot adelns motstånd') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e015', 'se', 'battle', 'stormakt', 'Slaget vid Narva', '20 november 1700', 1700, 59.377, 28.177, 'Narva, Estland', 'Svenska Estland, 1700', 'Stora Nordiska krigets första stora slag. Med 10 000 man besegrade Karl XII en rysk armé på 40 000 under Peter den Store. En av de mest imponerande segrarna i europeisk militärhistoria. Men segern var bedräglig – den gav Peter den Store tid att reformera sin armé.', NULL, NULL, 'Karl XII:s snabba marsch för att undsätta Narva') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e015', 'se_p007', 'Kung av Sverige, 18 år gammal, segerrik befälhavare') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e015', 'se_p008', 'Tsar av Ryssland, besegrad och tvingad att fly') ON CONFLICT (event_id, person_id) DO NOTHING;
