INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e015', 2, 59.38, 28.18, 'Narva – ryska belägringen bryts');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e016', 'se', 'battle', 'stormakt', 'Slaget vid Kliszów', '19 juli 1702', 1702, 50.317, 20.583, 'Kliszów, Polen', 'Kungariket Polen, 1702', 'Karl XII besegrade den sachsisk-polska armén och ockuperade Warszawa och Kraków. Sverige kontrollerade nu stora delar av Polen och Karl installerade en ny kung på den polska tronen. Det verkade som det svenska stormaktsimperiet nådde sin topp.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e016', 'se_p007', 'Kung av Sverige, segerrik i en lång rad polska fälttåg') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e017', 'se', 'battle', 'stormakt', 'Slaget vid Poltava', '8 juli 1709', 1709, 49.588, 34.55, 'Poltava, Ukraina', 'Det ryska tsarriket, 1709', 'Stormaktstidens avgörande vändpunkt. Karl XII hade marscherat in i det ryska tsarriket i vad som idag är Ukraina, försvagad av den hårdaste vintern på decennier. Den svenska armén – utmattad, underbemannad och utan ammunition – krossades av Peter den Stores numerärt överlägsna styrkor. Sverige förlorade 9 000 man och 14 000 kapitulerade. Karl flydde till det Osmanska riket. Det var stormaktstidens slut.', NULL, NULL, 'Den ödesdigra marschen in i Ukraina – genom den värsta vintern på ett sekel') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e017', 'se_p007', 'Kung av Sverige, sårad och besegrad, flydde till Osmanska riket') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e017', 'se_p008', 'Tsar av Ryssland, segrare – hämnades Narva') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e017', 'se_p016', 'Kosackhetman, Karl XII:s ukrainske allierade') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e017', 0, 52.23, 21.01, 'Warszawa – utgångspunkt 1708');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e017', 1, 52.4, 30.99, 'Homel – in i Ryssland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e017', 2, 51.5, 33.97, 'Baturyn – Mazepas säte bränns av Peter');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e017', 3, 50.45, 34.52, 'Vinter 1708–09 – den stora frosten');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e017', 4, 49.59, 34.55, 'Poltava – katastrofen');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e018', 'se', 'battle', 'stormakt', 'Slaget vid Gadebusch', '20 december 1712', 1712, 53.703, 11.117, 'Gadebusch, Tyskland', 'Hertigdömet Mecklenburg, 1712', 'Sveriges sista stora seger i Stora Nordiska kriget. Magnus Stenbock besegrade en dansk-sachsisk armé i norra Tyskland. Men segern var strategiskt meningslös – Sverige var omringat på alla fronter och Stenbock kapitulerade året därpå vid Tönning.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e018', 'se_p009', 'Svensk fältmarskalk, vann den sista svenska storsegern') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e019', 'se', 'event', 'fall', 'Karl XII skjuts vid Fredrikshald', '30 november 1718', 1718, 59.128, 11.387, 'Halden, Norge', 'Norge (dansk), 1718', 'Under belägringen av den norska fästningen Fredrikshald sköts Karl XII i huvudet i ett löpgravssystem. Omständigheterna är fortfarande historiskt omtvistade – var det ett fientligt skott eller ett attentat? Med hans död upphörde Sverige att föra krig och stormaktsepoken tog slut.', NULL, NULL, 'Karl XII:s extraordinära flykt – från Poltava till osmanerna och slutligen hem') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e019', 'se_p007', 'Kung av Sverige, stupade under oklara omständigheter') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e019', 0, 49.59, 34.55, 'Poltava – flykten börjar');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e019', 1, 47.84, 35.14, 'Zaporizjzja – passerar Dnjepr');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e019', 2, 46.84, 29.64, 'Bender, Moldavien – osmaniskt skydd');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e019', 3, 57.71, 11.97, 'Stralsund – återvänder 1714');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e019', 4, 59.13, 11.39, 'Fredrikshald – sköts 1718');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e020', 'se', 'event', 'fall', 'Freden i Nystad', '10 september 1721', 1721, 60.801, 21.375, 'Uusikaupunki, Finland', 'Kungariket Sverige, 1721', 'Stora Nordiska krigets slutliga uppgörelse. Sverige tvingades avträda Estland, Livland, Ingermanland och delar av Karelen till Ryssland. Det var ett av de mest kännbara territoriella förlusterna i svensk historia och markerade officiellt slutet på stormaktstiden. Ryssland tog över rollen som Östersjöns dominerande makt.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e020', 'se_p010', 'Drottning av Sverige, ratificerade freden') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e020', 'se_p008', 'Tsar av Ryssland, tog emot de baltiska provinserna') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e021', 'se', 'event', 'frihetstid', 'Frihetstiden inleds – ny författning', '1720', 1720, 59.325, 18.071, 'Stockholm, Sverige', 'Kungariket Sverige, 1720', 'Efter Karl XII:s död och stormaktstidens kostsamma krig förlorade kungamakten sin absoluta ställning. En ny regeringsform gav riksrådet och riksdagen makten. Sverige gick från envälde till en form av parlamentarisk styrelse – ovanligt för sin tid i Europa.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e021', 'se_p010', 'Drottning, accepterade den begränsade kungamakten') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e021', 'se_p011', 'Ledande politiker, arkitekt bakom den nya författningen') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e022', 'se', 'battle', 'frihetstid', 'Hattarnas krig mot Ryssland', '1741–1743', 1741, 60.45, 25.1, 'Helsingfors, Finland', 'Svenska Finland, 1741', 'Det krigsbejakande hattpartiet drev Sverige in i ett nytt krig mot Ryssland med förhoppning om att återta förlusterna från Nystad. Det slutade i katastrof. Sverige förlorade ytterligare territorium i Finland och tsarinan Elisabet dikterade fredsvillkoren. Kriget visade att stormaktstiden verkligen var förbi.', NULL, NULL, 'Hattarnas offensiv in i Finland – som snabbt slutade i katastrof') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e022', 'se_p017', 'Kung av Sverige, förde ett krig han inte kunde vinna') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e022', 0, 59.33, 18.07, 'Stockholm – mobilisering');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e022', 1, 60.39, 25.67, 'Helsingfors – anfall in i Finland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e022', 2, 60.45, 27.18, 'Fredrikshamn – fronten');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e023', 'se', 'event', 'gustaviansk', 'Gustaf III:s statskupp', '19 augusti 1772', 1772, 59.325, 18.071, 'Stockholm, Sverige', 'Kungariket Sverige, 1772', 'Gustaf III genomförde en närmast oblodig statskupp och återupprättade kungamakten. Han omringade riksdagen med trupper och tvingade fram en ny regeringsform som gav kungen tillbaka den verkliga makten. Frihetstiden var slut. Gustaf III var karismatisk, kultiverad och briljant – men också djupt auktoritär.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e023', 'se_p012', 'Kung av Sverige, genomförde kuppen personligen') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e024', 'se', 'battle', 'gustaviansk', 'Slaget vid Hogland', '17 juli 1788', 1788, 60.467, 26.983, 'Finska viken, internationellt vatten', 'Finska viken, 1788', 'Gustaf III startade krig mot Ryssland utan riksdagens godkännande och den svenska flottan mötte ryssarna vid Hogland i Finska viken. Resultatet var oavgjort men kriget var politiskt katastrofalt – officerarna vägrade lyda order och bildade Anjalaförbundet mot kungen.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e024', 'se_p012', 'Kung av Sverige, initierade kriget') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e025', 'se', 'battle', 'gustaviansk', 'Slaget vid Svensksund', '9–10 juli 1790', 1790, 60.55, 27.1, 'Kotka, Finland', 'Svenska Finland, 1790', 'Sveriges största flottaktig sett till antalet fartyg och den mest lysande svenska sjösegren i modern tid. Gustaf III ledde personligen en galärflotta mot ryssarna i Finska viken och vann en fullständig seger. Kungen jublade men freden som följde gav inga territoriella vinster.', NULL, NULL, 'Gustaf III:s galärflotta seglar österut mot den ryska flottan') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e025', 'se_p012', 'Kung av Sverige, ledde flottan personligen till seger') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e025', 0, 60.15, 25, 'Helsingfors – flottan samlas');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e025', 1, 60.42, 26.2, 'Pyttis – galärerna formeras');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e025', 2, 60.55, 27.1, 'Svensksund – den avgörande segern');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e026', 'se', 'event', 'gustaviansk', 'Gustaf III mördas på maskeradbal', '29 mars 1792', 1792, 59.325, 18.071, 'Stockholm, Sverige', 'Kungariket Sverige, 1792', 'Gustaf III sköts på en maskeradbal på Operan i Stockholm av Jacob Johan Anckarström, en del av en adelskonspiracy. Han dog av sina sår tretton dagar senare. Mordet inspirerade senare Verdis opera Un ballo in maschera. Hans son Gustaf IV Adolf, bara 13 år, ärvde tronen.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e026', 'se_p012', 'Kung av Sverige, mördad på maskeraden') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e027', 'se', 'battle', 'gustaviansk', 'Finska kriget – Ryssland invaderar', 'februari 1808', 1808, 60.45, 25.1, 'Helsingfors, Finland', 'Svenska Finland, 1808', 'Ryssland invaderade Finland i februari 1808 med Napoleons tysta samtycke. Gustaf IV Adolf vägrade kompromissa och förde ett katastrofalt krig. Den svenska armén retirerade hela vägen norrut och Finland föll i ryska händer. Det var den mest traumatiska territoriella förlusten i svensk historia.', NULL, NULL, 'Det ryska framrycket – Sverige retirerade hela vägen norrut') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e027', 'se_p013', 'Kung av Sverige, förde ett hopplöst försvarskrig') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e027', 0, 60.72, 28.75, 'Viborg – ryska armén bryter upp');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e027', 1, 60.45, 25.1, 'Helsingfors – faller i mars 1808');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e027', 2, 61.49, 23.77, 'Tammerfors – armén trycks norrut');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e027', 3, 64.83, 25.08, 'Siikajoki – sista svenska motståndet');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e028', 'se', 'battle', 'gustaviansk', 'Slaget vid Siikajoki', '18 april 1808', 1808, 64.833, 25.083, 'Siikajoki, Finland', 'Norra Finland, 1808', 'En av de få svenska segrarna under Finska kriget. Den svenska armén under Georg Carl von Döbeln stoppade det ryska framrycket tillfälligt i norra Finland. Men det förändrade inte krigets utgång – Ryssland hade överväldigande resurser och Finland var strategiskt förlorat.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e029', 'se', 'event', 'gustaviansk', 'Gustaf IV Adolf avsätts', '13 mars 1809', 1809, 59.325, 18.071, 'Stockholm, Sverige', 'Kungariket Sverige, 1809', 'Militärofficerare grep Gustaf IV Adolf i en kupp och avsatte honom. Han var den siste svenska kungen att störtas från tronen. Hans farbror Karl XIII tog makten som en kompromiss, men var gammal och barnlös. Sverige behövde en ny tronföljare – och blickade oväntat mot Frankrike.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e029', 'se_p013', 'Kung av Sverige, avsatt i militärkupp, gick i exil') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e030', 'se', 'event', 'slutet', 'Freden i Fredrikshamn – Finland förloras', '17 september 1809', 1809, 60.567, 27.2, 'Hamina, Finland', 'Finska viken, 1809', 'Sverige tvingades formellt avträda hela Finland till Ryssland. Finland hade varit en del av Sverige i över 600 år. Förlusten var ett nationellt trauma utan like och omformade den svenska självbilden fundamentalt. Sverige var nu ett litet nordeuropeiskt kungarike – stormaktstiden ett minne.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e031', 'se', 'event', 'slutet', 'Bernadotte väljs till kronprins', '21 augusti 1810', 1810, 58.592, 16.185, 'Örebro, Sverige', 'Kungariket Sverige, 1810', 'Den franske marskalken Jean-Baptiste Bernadotte valdes av riksdagen i Örebro till svensk kronprins – ett av historiens mer osannolika dynastiskiften. En napoleonsk general, som aldrig hade besökt Sverige, skulle nu leda landet. Han tog namnet Karl Johan och visade sig bli en av Sveriges mest framgångsrika statsöverhuvuden.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e031', 'se_p014', 'Fransk marskalk, vald till svensk kronprins') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e032', 'se', 'battle', 'slutet', 'Slaget vid Leipzig – Sverige mot Napoleon', '16–19 oktober 1813', 1813, 51.34, 12.375, 'Leipzig, Tyskland', 'Sachsen, 1813', 'Karl Johan ledde svenska trupper mot sin gamle chef Napoleon i ''Völkerschlacht'' – Nationernas slag. Sverige stred som en del av den sjätte koalitionen och bidrog till Napoleons avgörande nederlag. Karl Johans agerande var strategiskt klokt men ansågs av vissa som ett förräderi mot Frankrike.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e032', 'se_p014', 'Kronprins av Sverige, överbefälhavare för Nordtyska armén') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e033', 'se', 'battle', 'slutet', 'Karl Johan invaderar Danmark', 'januari 1814', 1814, 57.046, 9.919, 'Jylland, Danmark', 'Kungariket Danmark, 1814', 'Karl Johan marscherade in i Holstein och Jylland med en överlägsen armé. Danmark, som allierat sig med Napoleon, hade inget val. Trycket var omedelbart och effektivt. Inom veckor satt danskarna vid förhandlingsbordet.', NULL, NULL, 'Karl Johans snabba invasion – Danmark hade inget svar på den överlägsna armén') ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e033', 'se_p014', 'Kronprins av Sverige, ledde invasionen') ON CONFLICT (event_id, person_id) DO NOTHING;
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e033', 0, 53.55, 10, 'Hamburg-trakten – samlingsplats');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e033', 1, 54.31, 10.13, 'Kiel – in i Holstein');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e033', 2, 55.71, 9.52, 'Kolding – in i Jylland');
INSERT INTO event_waypoints (event_id, sort_order, lat, lng, label) VALUES ('se_e033', 3, 57.05, 9.92, 'Ålborg – Danmark kapitulerar');
INSERT INTO events (id, country_id, type, era_id, name, date, year, lat, lng, modern_location, historical_context, description, notes, wikipedia, route_description) VALUES ('se_e034', 'se', 'event', 'slutet', 'Freden i Kiel – Norge till Sverige', '14 januari 1814', 1814, 54.323, 10.133, 'Kiel, Tyskland', 'Hertgidömet Holstein, 1814', 'Danmark tvingades avträda Norge till Sverige i freden i Kiel – en direkt följd av Karl Johans invasion och Napoleons fall. Det avslutade formellt den långa konflikten mellan Sverige och Danmark som hade pågått i århundraden sedan Stockholms blodbad 1520. Berättelsens cirkel slöts.', NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO event_persons (event_id, person_id, role) VALUES ('se_e034', 'se_p014', 'Kronprins av Sverige, erhöll Norge som krigsvinst') ON CONFLICT (event_id, person_id) DO NOTHING;
